import{_ as e,o,c as d,ay as l}from"./chunks/framework.-lzFfN-z.js";const y=JSON.parse('{"title":"HTTP 请求头与响应头常见类型","description":"","frontmatter":{},"headers":[],"relativePath":"networkAndBrowsers/headers.md","filePath":"networkAndBrowsers/headers.md","lastUpdated":1779843930000}'),n={name:"networkAndBrowsers/headers.md"};function a(r,t,s,c,i,g){return o(),d("div",null,[...t[0]||(t[0]=[l('<h1 id="http-请求头与响应头常见类型" tabindex="-1">HTTP 请求头与响应头常见类型 <a class="header-anchor" href="#http-请求头与响应头常见类型" aria-label="Permalink to &quot;HTTP 请求头与响应头常见类型&quot;">​</a></h1><p>在 HTTP 协议中，Header（头部）是以键值对 <code>Key: Value</code> 形式存在的元数据，它们负责在客户端（如浏览器）和服务器之间传递控制信息、状态信息以及对数据的描述。</p><p>为了便于理解，我们将最常用的 HTTP 头部按<strong>流向</strong>和<strong>功能</strong>分为三大类：请求头、响应头和实体头（描述正文数据的头，两者皆可使用）。</p><h2 id="_1-常见请求头-request-headers" tabindex="-1">1. 常见请求头 (Request Headers) <a class="header-anchor" href="#_1-常见请求头-request-headers" aria-label="Permalink to &quot;1. 常见请求头 (Request Headers)&quot;">​</a></h2><p><strong>流向：客户端 -&gt; 服务器。</strong> 用于向服务器传递客户端的自身属性、用户的偏好设置以及请求的上下文信息。</p><h3 id="_1-1-客户端信息与内容协商-告诉服务器-我是谁-我要什么" tabindex="-1">1.1 客户端信息与内容协商 (告诉服务器“我是谁，我要什么”) <a class="header-anchor" href="#_1-1-客户端信息与内容协商-告诉服务器-我是谁-我要什么" aria-label="Permalink to &quot;1.1 客户端信息与内容协商 (告诉服务器“我是谁，我要什么”)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">字段名</th><th style="text-align:left;">说明</th><th style="text-align:left;">常见值 / 示例</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>User-Agent</code></strong></td><td style="text-align:left;">包含了发出请求的客户端（浏览器、操作系统）的详细信息。常用于服务器进行设备判断（PC 还是移动端）或数据统计。</td><td style="text-align:left;"><code>Mozilla/5.0 (Windows NT 10.0; Win64; x64)...</code></td></tr><tr><td style="text-align:left;"><strong><code>Accept</code></strong></td><td style="text-align:left;">告诉服务器客户端<strong>期望接收</strong>的数据格式（MIME 类型）。</td><td style="text-align:left;"><code>application/json</code>, <code>text/html</code>, <code>image/webp</code></td></tr><tr><td style="text-align:left;"><strong><code>Accept-Encoding</code></strong></td><td style="text-align:left;">告诉服务器客户端支持的<strong>内容压缩格式</strong>，服务器可据此压缩响应体积。</td><td style="text-align:left;"><code>gzip, deflate, br</code> (Brotli)</td></tr><tr><td style="text-align:left;"><strong><code>Accept-Language</code></strong></td><td style="text-align:left;">告诉服务器客户端偏好的语言，用于国际化（i18n）多语言支持。</td><td style="text-align:left;"><code>zh-CN, zh;q=0.9, en;q=0.8</code></td></tr></tbody></table><h3 id="_1-2-身份验证与状态维持" tabindex="-1">1.2 身份验证与状态维持 <a class="header-anchor" href="#_1-2-身份验证与状态维持" aria-label="Permalink to &quot;1.2 身份验证与状态维持&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">字段名</th><th style="text-align:left;">说明</th><th style="text-align:left;">常见值 / 示例</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>Authorization</code></strong></td><td style="text-align:left;">携带身份验证凭证（如 Token 或账号密码），证明客户端有权访问该 API 接口。</td><td style="text-align:left;"><code>Bearer eyJhbGciOiJIUzI1Ni...</code><br><code>Basic YWRtaW46MTIzNDU2</code></td></tr><tr><td style="text-align:left;"><strong><code>Cookie</code></strong></td><td style="text-align:left;">将浏览器本地存储的、属于该域名的 Cookie 数据发送给服务器，用于维持登录状态（Session）或用户追踪。</td><td style="text-align:left;"><code>sessionId=123abc456def; theme=dark</code></td></tr></tbody></table><h3 id="_1-3-路由、来源与安全-cors" tabindex="-1">1.3 路由、来源与安全 (CORS) <a class="header-anchor" href="#_1-3-路由、来源与安全-cors" aria-label="Permalink to &quot;1.3 路由、来源与安全 (CORS)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">字段名</th><th style="text-align:left;">说明</th><th style="text-align:left;">常见值 / 示例</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>Host</code></strong></td><td style="text-align:left;"><strong>(HTTP/1.1 唯一必填字段)</strong> 指定请求的服务器域名和端口号。用于物理服务器区分不同的虚拟主机（同一 IP 下的不同网站）。</td><td style="text-align:left;"><code>www.example.com</code><br><code>api.example.com:8080</code></td></tr><tr><td style="text-align:left;"><strong><code>Referer</code></strong></td><td style="text-align:left;">记录了当前请求是<strong>从哪个页面的 URL 跳转或发起</strong>的。常用于防盗链（防止别人引用你的图片）和流量分析。（注：历史上拼写错误，少了一个 r，沿用至今）。</td><td style="text-align:left;"><code>https://www.google.com/</code></td></tr><tr><td style="text-align:left;"><strong><code>Origin</code></strong></td><td style="text-align:left;">发起<strong>跨域请求 (CORS)</strong> 时由浏览器自动携带，只包含协议+域名+端口，不包含路径。用于服务器判断是否允许跨域。</td><td style="text-align:left;"><code>https://www.myfrontend.com</code></td></tr></tbody></table><h3 id="_1-4-协商缓存验证-配合响应头使用" tabindex="-1">1.4 协商缓存验证 (配合响应头使用) <a class="header-anchor" href="#_1-4-协商缓存验证-配合响应头使用" aria-label="Permalink to &quot;1.4 协商缓存验证 (配合响应头使用)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">字段名</th><th style="text-align:left;">说明</th><th style="text-align:left;">常见值 / 示例</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>If-None-Match</code></strong></td><td style="text-align:left;">将上次服务器给的 <code>ETag</code> 值发回，询问服务器资源变了没。没变则服务器返回 304。</td><td style="text-align:left;"><code>&quot;33a64df551425fcc...&quot;</code></td></tr><tr><td style="text-align:left;"><strong><code>If-Modified-Since</code></strong></td><td style="text-align:left;">将上次服务器给的 <code>Last-Modified</code> 值发回，询问自该时间后资源修改了没。</td><td style="text-align:left;"><code>Wed, 21 Oct 2026 07:28:00 GMT</code></td></tr></tbody></table><h2 id="_2-常见响应头-response-headers" tabindex="-1">2. 常见响应头 (Response Headers) <a class="header-anchor" href="#_2-常见响应头-response-headers" aria-label="Permalink to &quot;2. 常见响应头 (Response Headers)&quot;">​</a></h2><p><strong>流向：服务器 -&gt; 客户端。</strong> 用于向客户端传递服务器自身信息、指示客户端进行特定操作（如重定向、存 Cookie）以及跨域权限配置。</p><h3 id="_2-1-状态指示与控制" tabindex="-1">2.1 状态指示与控制 <a class="header-anchor" href="#_2-1-状态指示与控制" aria-label="Permalink to &quot;2.1 状态指示与控制&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">字段名</th><th style="text-align:left;">说明</th><th style="text-align:left;">常见值 / 示例</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>Server</code></strong></td><td style="text-align:left;">包含了处理请求的服务器软件及其版本信息（出于安全考虑，常被隐藏或修改）。</td><td style="text-align:left;"><code>nginx/1.20.1</code>, <code>Apache</code>, <code>Tengine</code></td></tr><tr><td style="text-align:left;"><strong><code>Set-Cookie</code></strong></td><td style="text-align:left;">服务器通过此字段<strong>命令浏览器保存 Cookie</strong>。可以设置过期时间 (<code>Expires</code>)、生效路径 (<code>Path</code>)、仅限 HTTP 访问 (<code>HttpOnly</code>) 等属性。</td><td style="text-align:left;"><code>sessionid=xyz123; HttpOnly; Secure; Path=/</code></td></tr><tr><td style="text-align:left;"><strong><code>Location</code></strong></td><td style="text-align:left;">通常与 <code>3xx</code>（如 301, 302）状态码配合使用，**命令浏览器跳转（重定向）**到新的 URL 地址。</td><td style="text-align:left;"><code>https://www.new-domain.com/login</code></td></tr><tr><td style="text-align:left;"><strong><code>Content-Disposition</code></strong></td><td style="text-align:left;">指示浏览器应当如何处理响应内容。是直接在页面内展示（<code>inline</code>），还是当作<strong>附件下载</strong>（<code>attachment</code>）。</td><td style="text-align:left;"><code>attachment; filename=&quot;report.xlsx&quot;</code></td></tr></tbody></table><h3 id="_2-2-缓存控制-强缓存与协商缓存" tabindex="-1">2.2 缓存控制 (强缓存与协商缓存) <a class="header-anchor" href="#_2-2-缓存控制-强缓存与协商缓存" aria-label="Permalink to &quot;2.2 缓存控制 (强缓存与协商缓存)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">字段名</th><th style="text-align:left;">说明</th><th style="text-align:left;">常见值 / 示例</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>Cache-Control</code></strong></td><td style="text-align:left;"><strong>最核心的缓存控制指令</strong>。规定了资源在客户端可以缓存多久，或者是否需要每次都验证。</td><td style="text-align:left;"><code>max-age=3600</code><br><code>no-cache</code> (需协商验证)<br><code>no-store</code> (绝对不缓存)</td></tr><tr><td style="text-align:left;"><strong><code>ETag</code></strong></td><td style="text-align:left;">资源内容的唯一标识符（类似于哈希/指纹）。资源内容改变，ETag 就会改变。</td><td style="text-align:left;"><code>&quot;W/123456789&quot;</code></td></tr><tr><td style="text-align:left;"><strong><code>Last-Modified</code></strong></td><td style="text-align:left;">资源在服务器上的最后修改时间。</td><td style="text-align:left;"><code>Mon, 23 Feb 2026 12:00:00 GMT</code></td></tr></tbody></table><h3 id="_2-3-跨域资源共享-cors-核心" tabindex="-1">2.3 跨域资源共享 (CORS 核心) <a class="header-anchor" href="#_2-3-跨域资源共享-cors-核心" aria-label="Permalink to &quot;2.3 跨域资源共享 (CORS 核心)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">字段名</th><th style="text-align:left;">说明</th><th style="text-align:left;">常见值 / 示例</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>Access-Control-Allow-Origin</code></strong></td><td style="text-align:left;">服务器明确宣告：<strong>允许哪些来源（Origin）的前端代码跨域访问我的资源</strong>。</td><td style="text-align:left;"><code>*</code> (允许所有，极度危险)<br><code>https://www.myfrontend.com</code></td></tr><tr><td style="text-align:left;"><strong><code>Access-Control-Allow-Methods</code></strong></td><td style="text-align:left;">在预检请求（OPTIONS）中返回，告知前端跨域请求被允许使用哪些 HTTP 方法。</td><td style="text-align:left;"><code>GET, POST, PUT, DELETE</code></td></tr><tr><td style="text-align:left;"><strong><code>Access-Control-Allow-Credentials</code></strong></td><td style="text-align:left;">是否允许前端跨域请求携带 Cookie。如果设为 <code>true</code>，<code>Allow-Origin</code> 绝对不能设为 <code>*</code>。</td><td style="text-align:left;"><code>true</code></td></tr></tbody></table><h2 id="_3-实体头-entity-headers" tabindex="-1">3. 实体头 (Entity Headers) <a class="header-anchor" href="#_3-实体头-entity-headers" aria-label="Permalink to &quot;3. 实体头 (Entity Headers)&quot;">​</a></h2><p><strong>既可用于请求，也可用于响应。</strong> 专门用来描述请求正文（Request Body）或响应正文（Response Body）的数据特征。</p><table tabindex="0"><thead><tr><th style="text-align:left;">字段名</th><th style="text-align:left;">说明</th><th style="text-align:left;">常见值 / 示例</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>Content-Type</code></strong></td><td style="text-align:left;"><strong>极其重要！</strong> 明确告知接收方：<strong>Body 里的数据到底是什么格式</strong>，以及采用了什么字符编码。接收方靠它来决定如何解析数据。</td><td style="text-align:left;"><code>application/json; charset=utf-8</code><br><code>application/x-www-form-urlencoded</code><br><code>image/png</code></td></tr><tr><td style="text-align:left;"><strong><code>Content-Length</code></strong></td><td style="text-align:left;">明确指出 Body 数据的大小（字节数）。让接收方知道何时接收完毕。</td><td style="text-align:left;"><code>1024</code></td></tr><tr><td style="text-align:left;"><strong><code>Content-Encoding</code></strong></td><td style="text-align:left;">表明 Body 数据在网络传输前<strong>实际采用了哪种压缩算法</strong>。接收方收到后必须用同种算法解压。</td><td style="text-align:left;"><code>gzip</code>, <code>br</code></td></tr></tbody></table><h2 id="_4-常见问题-faq-与经典面试题" tabindex="-1">4. 常见问题 (FAQ) 与经典面试题 <a class="header-anchor" href="#_4-常见问题-faq-与经典面试题" aria-label="Permalink to &quot;4. 常见问题 (FAQ) 与经典面试题&quot;">​</a></h2><h3 id="_4-1-accept-和-content-type-到底有什么区别" tabindex="-1">4.1 <code>Accept</code> 和 <code>Content-Type</code> 到底有什么区别？ <a class="header-anchor" href="#_4-1-accept-和-content-type-到底有什么区别" aria-label="Permalink to &quot;4.1 `Accept` 和 `Content-Type` 到底有什么区别？&quot;">​</a></h3><p>这是一个极度容易混淆的概念：</p><ul><li><strong><code>Accept</code> (只在请求头里)</strong>：是<strong>接收方</strong>的期望。客户端对服务器说：“我<strong>希望</strong>你给我返回 <code>application/json</code> 格式的数据”。</li><li><strong><code>Content-Type</code> (请求和响应都有)</strong>：是<strong>发送方</strong>的声明。 <ul><li>在请求里：客户端对服务器说：“我塞在 Body 传给你的数据<strong>实际是</strong> <code>application/json</code>”。</li><li>在响应里：服务器对客户端说：“我查完数据库了，现在返回给你的 Body 数据<strong>实际是</strong> <code>application/json</code>”。</li></ul></li></ul><h3 id="_4-2-前后端分离跨域时-请求头和响应头是如何配合的" tabindex="-1">4.2 前后端分离跨域时，请求头和响应头是如何配合的？ <a class="header-anchor" href="#_4-2-前后端分离跨域时-请求头和响应头是如何配合的" aria-label="Permalink to &quot;4.2 前后端分离跨域时，请求头和响应头是如何配合的？&quot;">​</a></h3><p>跨域（CORS）是一场前端浏览器与后端服务器之间的“安全握手”：</p><ul><li><strong>请求头出击</strong>：浏览器发现你在跨域，会自动在请求头加上 <code>Origin: http://前端域名.com</code>。</li><li><strong>响应头裁决</strong>：后端服务器收到请求，检查这个 <code>Origin</code>。如果同意，就在响应头里加上 <code>Access-Control-Allow-Origin: http://前端域名.com</code>。</li><li><strong>浏览器放行</strong>：浏览器收到响应，核对请求的 <code>Origin</code> 和响应的 <code>Allow-Origin</code> 是否匹配。匹配则把数据交给 JavaScript；不匹配则在控制台抛出著名的 CORS 跨域红字报错。</li></ul><h3 id="_4-3-cookie-和-set-cookie-是如何实现状态保持的" tabindex="-1">4.3 <code>Cookie</code> 和 <code>Set-Cookie</code> 是如何实现状态保持的？ <a class="header-anchor" href="#_4-3-cookie-和-set-cookie-是如何实现状态保持的" aria-label="Permalink to &quot;4.3 `Cookie` 和 `Set-Cookie` 是如何实现状态保持的？&quot;">​</a></h3><p>HTTP 本身不记仇（无状态），它们俩配合实现了“记忆”：</p><ol><li>你输入账号密码登录，服务器验证成功。</li><li>服务器在<strong>响应头</strong>中下发：<code>Set-Cookie: session_id=888; HttpOnly</code>。</li><li>浏览器看到 <code>Set-Cookie</code>，默默把它存到本地硬盘或内存里。</li><li>之后你点开网站的任何其他页面，浏览器会自动在<strong>请求头</strong>中携带：<code>Cookie: session_id=888</code>。</li><li>服务器读取请求头里的 <code>Cookie</code>，一看是 <code>888</code>，就知道是你，直接放行。</li></ol><h3 id="_4-4-什么是自定义请求头-如何设置" tabindex="-1">4.4 什么是自定义请求头？如何设置？ <a class="header-anchor" href="#_4-4-什么是自定义请求头-如何设置" aria-label="Permalink to &quot;4.4 什么是自定义请求头？如何设置？&quot;">​</a></h3><p>业务开发中，我们经常需要传递标准协议之外的信息（如 Token、设备 ID 等）。</p><ul><li><strong>旧规范</strong>：过去习惯加 <code>X-</code> 前缀（如 <code>X-Requested-With</code>, <code>X-Token</code>），但这已被 IETF 官方废弃，因为容易造成命名混乱。</li><li><strong>新规范</strong>：直接使用清晰达意的英文单词连字符命名即可，比如 <code>Api-Version</code>, <code>App-Device-Id</code>。</li><li><strong>注意（跨域陷阱）</strong>：如果前端跨域发送了<strong>自定义请求头</strong>，会触发浏览器的“预检请求（OPTIONS）”。后端必须在响应头 <code>Access-Control-Allow-Headers</code> 中明确允许这个自定义头（例如 <code>Access-Control-Allow-Headers: Content-Type, App-Device-Id</code>），否则跨域会失败。</li></ul><h3 id="_4-5-accept-encoding-和-content-encoding-的配合机制" tabindex="-1">4.5 <code>Accept-Encoding</code> 和 <code>Content-Encoding</code> 的配合机制？ <a class="header-anchor" href="#_4-5-accept-encoding-和-content-encoding-的配合机制" aria-label="Permalink to &quot;4.5 `Accept-Encoding` 和 `Content-Encoding` 的配合机制？&quot;">​</a></h3><ol><li>浏览器在请求头带上 <code>Accept-Encoding: gzip, br</code>，表示：“我支持解压 gzip 和 brotli”。</li><li>服务器看到后，挑一个自己支持且压缩率最高的（比如 gzip），把响应 Body 压缩。</li><li>服务器在响应头带上 <code>Content-Encoding: gzip</code> 发给浏览器，表示：“我用 gzip 压缩过了”。</li><li>浏览器收到后，看到 <code>gzip</code> 标记，就用 gzip 算法解压 Body，然后渲染页面。如果两边不一致，页面就会显示乱码。</li></ol>',39)])])}const f=e(n,[["render",a]]);export{y as __pageData,f as default};
